func remapNvidia(context *model.KopsModelContext, addon *addonsapi.AddonSpec, objects kubemanifest.ObjectList) error {
	version := ""
	if context != nil && context.Cluster != nil && context.Cluster.Spec.Containerd != nil && context.Cluster.Spec.Containerd.NvidiaGPU != nil && context.Cluster.Spec.Containerd.NvidiaGPU.DevicePluginVersion != nil {
		version = fi.ValueOf(context.Cluster.Spec.Containerd.NvidiaGPU.DevicePluginVersion)
	}
	if version == "" {
		return nil
	}

	for _, object := range objects {
		if object.Kind() != "DaemonSet" || object.GetName() != "nvidia-device-plugin-daemonset" {
			continue
		}

		if err := object.VisitContainers(func(container map[string]interface{}) error {
			image, ok := container["image"].(string)
			if !ok || image == "" {
				return nil
			}
			// Replace the tag portion (everything after the last colon). If there is no colon, append the tag.
			lastColon := -1
			for i := len(image) - 1; i >= 0; i-- {
				if image[i] == ':' {
					lastColon = i
					break
				}
				// stop before registry port separator
				if image[i] == '/' {
					break
				}
			}
			if lastColon != -1 {
				image = image[:lastColon]
			}
			container["image"] = image + ":" + version
			return nil
		}); err != nil {
			return fmt.Errorf("error visiting containers: %w", err)
		}
	}

	return nil
}

