func TestRemapAddonManifest_NvidiaDevicePluginVersion(t *testing.T) {
	cluster := testutils.NewCluster()
	cluster.Spec.Containerd = &model.ContainerdConfig{}
	cluster.Spec.Containerd.NvidiaGPU = &model.NvidiaGPUConfig{}
	cluster.Spec.Containerd.NvidiaGPU.DevicePluginVersion = fi.PtrTo("0.17.2")

	ctx := &model.KopsModelContext{Cluster: cluster}

	addon := &addonsapi.AddonSpec{Name: fi.PtrTo("nvidia.addons.k8s.io"), Selector: map[string]string{"k8s-addon": "nvidia.addons.k8s.io"}}

	in := []byte(`apiVersion: apps/v1
kind: DaemonSet
metadata:
  name: nvidia-device-plugin-daemonset
  namespace: kube-system
spec:
  template:
    spec:
      containers:
      - name: nvidia-device-plugin-ctr
        image: nvcr.io/nvidia/k8s-device-plugin:v0.12.2
`)

	out, err := RemapAddonManifest(addon, ctx, assets.NewAssetBuilder(cluster), in, nil)
